import{_ as o,C as i,o as d,c as l,a2 as e,b as c,w as r,a as h,E as n,a3 as _}from"./chunks/framework.DRBHoC6Q.js";const f=JSON.parse('{"title":"CEO 现金流驾驶舱 V3 数据库表结构与字段字典","description":"","frontmatter":{},"headers":[],"relativePath":"V3_数据库表结构与字段字典.md","filePath":"V3_数据库表结构与字段字典.md","lastUpdated":1783323851000}'),s={name:"V3_数据库表结构与字段字典.md"};function p(u,t,b,m,v,C){const a=i("Mermaid");return d(),l("div",null,[t[1]||(t[1]=e('<h1 id="ceo-现金流驾驶舱-v3-数据库表结构与字段字典" tabindex="-1">CEO 现金流驾驶舱 V3 数据库表结构与字段字典 <a class="header-anchor" href="#ceo-现金流驾驶舱-v3-数据库表结构与字段字典" aria-label="Permalink to &quot;CEO 现金流驾驶舱 V3 数据库表结构与字段字典&quot;">​</a></h1><p>文档版本：V0.1<br> 适用阶段：阶段 3——真实样本验证<br> 目标读者：产品经理、CFO/财务、前端、后端<br> 文档状态：技术基线，业务口径待 CFO 确认</p><h2 id="_1-目的与边界" tabindex="-1">1. 目的与边界 <a class="header-anchor" href="#_1-目的与边界" aria-label="Permalink to &quot;1. 目的与边界&quot;">​</a></h2><p>本文定义驾驶舱计算必须具备的标准数据模型。它不是对财务现有 Excel 的复制，也不是最终 ERP 数据模型。</p><p>真实报表通过导入映射转换为本模型：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>财务原始报表 → 原始行留存 → 字段映射与校验 → 标准业务表 → 指标/风险/任务计算 → 驾驶舱</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>V3 只覆盖账户余额、应收款、实际回款、计划支出、责任人和跟进闭环。预算、合同、付款审批、银行接口和完整权限不在本版冻结范围内。</p><h2 id="_2-建模原则" tabindex="-1">2. 建模原则 <a class="header-anchor" href="#_2-建模原则" aria-label="Permalink to &quot;2. 建模原则&quot;">​</a></h2><ol><li>业务表只保存原始事实；逾期天数、未回金额、风险等级、现金流缺口由系统计算。</li><li>每条标准业务数据保留 <code>import_batch_id</code>，能够追溯到导入批次和原始行。</li><li>金额统一按“元”保存，数据库使用 <code>numeric(18,2)</code>，禁止浮点数。</li><li>日期使用 <code>date</code>，操作时间使用带时区的 <code>timestamptz</code>。</li><li>已发布数据不物理删除，通过作废或更正保留历史。</li><li>V3 按“整批发布”处理；同一时点仅一个批次作为驾驶舱当前数据版本。</li><li>财务报表格式变化由导入适配层处理，不能直接推动核心业务表频繁变化。</li></ol><h2 id="_3-实体关系" tabindex="-1">3. 实体关系 <a class="header-anchor" href="#_3-实体关系" aria-label="Permalink to &quot;3. 实体关系&quot;">​</a></h2>',10)),(d(),c(_,null,{default:r(()=>[n(a,{id:"mermaid-62",class:"mermaid",graph:"erDiagram%0A%20%20IMPORT_BATCH%20%7C%7C--o%7B%20RAW_IMPORT_ROW%20%3A%20contains%0A%20%20IMPORT_BATCH%20%7C%7C--o%7B%20ACCOUNT_BALANCE%20%3A%20imports%0A%20%20IMPORT_BATCH%20%7C%7C--o%7B%20RECEIVABLE%20%3A%20imports%0A%20%20IMPORT_BATCH%20%7C%7C--o%7B%20COLLECTION%20%3A%20imports%0A%20%20IMPORT_BATCH%20%7C%7C--o%7B%20PLANNED_EXPENSE%20%3A%20imports%0A%20%20CUSTOMER%20%7C%7C--o%7B%20RECEIVABLE%20%3A%20owns%0A%20%20RECEIVABLE%20%7C%7C--o%7B%20COLLECTION%20%3A%20receives%0A%20%20RECEIVABLE%20%7C%7C--o%7B%20FOLLOWUP_RECORD%20%3A%20tracks%0A%20%20RECEIVABLE%20%7C%7C--o%7B%20TASK%20%3A%20generates%0A%20%20PLANNED_EXPENSE%20%7C%7C--o%7B%20TASK%20%3A%20generates%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[h(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e('<h2 id="_4-通用字段约定" tabindex="-1">4. 通用字段约定 <a class="header-anchor" href="#_4-通用字段约定" aria-label="Permalink to &quot;4. 通用字段约定&quot;">​</a></h2><p>除特别说明外，业务表包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>uuid</td><td>是</td><td>系统主键</td></tr><tr><td>import_batch_id</td><td>uuid</td><td>是</td><td>来源导入批次</td></tr><tr><td>source_row_no</td><td>integer</td><td>否</td><td>原 Excel 行号，用于追溯</td></tr><tr><td>status</td><td>varchar(20)</td><td>是</td><td>active / voided</td></tr><tr><td>created_at</td><td>timestamptz</td><td>是</td><td>创建时间</td></tr><tr><td>updated_at</td><td>timestamptz</td><td>是</td><td>更新时间</td></tr><tr><td>version</td><td>integer</td><td>是</td><td>乐观锁版本，初始为 1</td></tr></tbody></table><h2 id="_5-表结构与字段字典" tabindex="-1">5. 表结构与字段字典 <a class="header-anchor" href="#_5-表结构与字段字典" aria-label="Permalink to &quot;5. 表结构与字段字典&quot;">​</a></h2><h3 id="_5-1-import-batch——导入批次" tabindex="-1">5.1 import_batch——导入批次 <a class="header-anchor" href="#_5-1-import-batch——导入批次" aria-label="Permalink to &quot;5.1 import_batch——导入批次&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>约束/示例</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>uuid</td><td>是</td><td>PK</td><td>批次主键</td></tr><tr><td>batch_no</td><td>varchar(40)</td><td>是</td><td>UNIQUE</td><td>业务可读批次号</td></tr><tr><td>file_name</td><td>varchar(255)</td><td>是</td><td></td><td>原文件名</td></tr><tr><td>file_sha256</td><td>char(64)</td><td>是</td><td>INDEX</td><td>文件摘要，用于识别重复文件</td></tr><tr><td>template_version</td><td>varchar(20)</td><td>是</td><td><code>V0.1</code></td><td>模板版本</td></tr><tr><td>data_period_start</td><td>date</td><td>是</td><td></td><td>样本数据开始日期</td></tr><tr><td>data_period_end</td><td>date</td><td>是</td><td>&gt;= start</td><td>样本数据结束日期</td></tr><tr><td>status</td><td>varchar(24)</td><td>是</td><td>uploaded/parsing/validation_failed/pending_review/published/voided</td><td>批次状态</td></tr><tr><td>total_rows</td><td>integer</td><td>是</td><td>&gt;= 0</td><td>总行数</td></tr><tr><td>valid_rows</td><td>integer</td><td>是</td><td>&gt;= 0</td><td>校验通过行数</td></tr><tr><td>error_rows</td><td>integer</td><td>是</td><td>&gt;= 0</td><td>错误行数</td></tr><tr><td>warning_rows</td><td>integer</td><td>是</td><td>&gt;= 0</td><td>警告行数</td></tr><tr><td>uploaded_by</td><td>varchar(100)</td><td>是</td><td></td><td>V3 可存账号或操作者名称</td></tr><tr><td>published_by</td><td>varchar(100)</td><td>否</td><td></td><td>发布人</td></tr><tr><td>published_at</td><td>timestamptz</td><td>否</td><td></td><td>发布时间</td></tr><tr><td>created_at</td><td>timestamptz</td><td>是</td><td></td><td>创建时间</td></tr><tr><td>updated_at</td><td>timestamptz</td><td>是</td><td></td><td>更新时间</td></tr><tr><td>version</td><td>integer</td><td>是</td><td>default 1</td><td>乐观锁</td></tr></tbody></table><p>关键规则：同一文件摘要重复上传返回冲突；发布时必须无阻断错误；发布动作需要幂等。</p><h3 id="_5-2-raw-import-row——原始导入行" tabindex="-1">5.2 raw_import_row——原始导入行 <a class="header-anchor" href="#_5-2-raw-import-row——原始导入行" aria-label="Permalink to &quot;5.2 raw_import_row——原始导入行&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>uuid</td><td>是</td><td>主键</td></tr><tr><td>import_batch_id</td><td>uuid</td><td>是</td><td>导入批次</td></tr><tr><td>sheet_name</td><td>varchar(100)</td><td>是</td><td>原 Sheet 名称</td></tr><tr><td>row_no</td><td>integer</td><td>是</td><td>原始行号</td></tr><tr><td>raw_data</td><td>jsonb</td><td>是</td><td>原始表头和值，不做业务解释</td></tr><tr><td>normalized_data</td><td>jsonb</td><td>否</td><td>映射后的标准字段预览</td></tr><tr><td>validation_status</td><td>varchar(16)</td><td>是</td><td>valid/warning/error</td></tr><tr><td>validation_messages</td><td>jsonb</td><td>是</td><td>字段级错误数组</td></tr><tr><td>created_at</td><td>timestamptz</td><td>是</td><td>创建时间</td></tr></tbody></table><p>唯一约束：<code>(import_batch_id, sheet_name, row_no)</code>。</p><h3 id="_5-3-account-balance——账户余额快照" tabindex="-1">5.3 account_balance——账户余额快照 <a class="header-anchor" href="#_5-3-account-balance——账户余额快照" aria-label="Permalink to &quot;5.3 account_balance——账户余额快照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>Excel 字段</th><th>业务定义/校验</th></tr></thead><tbody><tr><td>account_code</td><td>varchar(64)</td><td>是</td><td>账户编号</td><td>账户稳定标识，不使用银行账号明文</td></tr><tr><td>account_name</td><td>varchar(120)</td><td>是</td><td>账户名称</td><td>脱敏展示名称</td></tr><tr><td>snapshot_date</td><td>date</td><td>是</td><td>快照日期</td><td>余额对应日期</td></tr><tr><td>available_balance</td><td>numeric(18,2)</td><td>是</td><td>可用余额（元）</td><td>可为 0，不得小于 0；负数场景待 CFO 确认</td></tr><tr><td>currency</td><td>char(3)</td><td>是</td><td>币种</td><td>V3 默认 CNY</td></tr><tr><td>restricted_amount</td><td>numeric(18,2)</td><td>否</td><td>受限金额（元）</td><td>默认 0；是否从可用余额扣除待确认</td></tr><tr><td>remark</td><td>varchar(500)</td><td>否</td><td>备注</td><td></td></tr></tbody></table><p>唯一约束：<code>(account_code, snapshot_date, import_batch_id)</code>。</p><h3 id="_5-4-customer——客户" tabindex="-1">5.4 customer——客户 <a class="header-anchor" href="#_5-4-customer——客户" aria-label="Permalink to &quot;5.4 customer——客户&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>Excel 来源</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>uuid</td><td>是</td><td>系统生成</td><td>主键</td></tr><tr><td>customer_code</td><td>varchar(64)</td><td>是</td><td>应收款.客户编号</td><td>稳定唯一标识</td></tr><tr><td>customer_name</td><td>varchar(200)</td><td>是</td><td>应收款.客户名称</td><td>V3 使用脱敏名称</td></tr><tr><td>customer_level</td><td>varchar(20)</td><td>否</td><td>客户等级</td><td>normal/key；是否参与风险待确认</td></tr><tr><td>active</td><td>boolean</td><td>是</td><td></td><td>默认 true</td></tr><tr><td>created_at</td><td>timestamptz</td><td>是</td><td></td><td>创建时间</td></tr><tr><td>updated_at</td><td>timestamptz</td><td>是</td><td></td><td>更新时间</td></tr></tbody></table><p>V3 可由应收导入时按 <code>customer_code</code> 自动建立或更新，不要求单独客户模板。</p><h3 id="_5-5-receivable——应收事项" tabindex="-1">5.5 receivable——应收事项 <a class="header-anchor" href="#_5-5-receivable——应收事项" aria-label="Permalink to &quot;5.5 receivable——应收事项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>Excel 字段</th><th>业务定义/校验</th></tr></thead><tbody><tr><td>receivable_no</td><td>varchar(64)</td><td>是</td><td>应收编号</td><td>全局稳定编号</td></tr><tr><td>customer_id</td><td>uuid</td><td>是</td><td>客户编号映射</td><td>关联客户</td></tr><tr><td>business_ref_no</td><td>varchar(64)</td><td>否</td><td>合同/业务编号</td><td>用于外部追溯，不作为 V3 必填</td></tr><tr><td>receivable_amount</td><td>numeric(18,2)</td><td>是</td><td>应收金额（元）</td><td>本应收事项原始应收额，必须 &gt; 0</td></tr><tr><td>agreed_due_date</td><td>date</td><td>是</td><td>约定到账日期</td><td>逾期判断基准</td></tr><tr><td>expected_date</td><td>date</td><td>否</td><td>预计到账日期</td><td>若为空，V3 暂以约定到账日作为预计日，待 CFO 确认</td></tr><tr><td>owner_code</td><td>varchar(64)</td><td>是</td><td>责任人编号</td><td>稳定标识</td></tr><tr><td>owner_name</td><td>varchar(100)</td><td>是</td><td>责任人名称</td><td>展示名称</td></tr><tr><td>business_line</td><td>varchar(100)</td><td>否</td><td>业务线</td><td>后续分析维度</td></tr><tr><td>source_status</td><td>varchar(20)</td><td>是</td><td>业务状态</td><td>open/cancelled；不得导入“已逾期”等计算状态</td></tr><tr><td>remark</td><td>varchar(500)</td><td>否</td><td>备注</td><td></td></tr></tbody></table><p>唯一约束：<code>(receivable_no, import_batch_id)</code>；发布版本内 <code>receivable_no</code> 唯一。</p><h3 id="_5-6-collection——实际回款" tabindex="-1">5.6 collection——实际回款 <a class="header-anchor" href="#_5-6-collection——实际回款" aria-label="Permalink to &quot;5.6 collection——实际回款&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>Excel 字段</th><th>业务定义/校验</th></tr></thead><tbody><tr><td>collection_no</td><td>varchar(64)</td><td>是</td><td>回款编号</td><td>唯一到账事件编号</td></tr><tr><td>receivable_id</td><td>uuid</td><td>是</td><td>应收编号映射</td><td>V3 一笔回款只对应一笔应收</td></tr><tr><td>collection_date</td><td>date</td><td>是</td><td>回款日期</td><td>实际到账日期</td></tr><tr><td>collection_amount</td><td>numeric(18,2)</td><td>是</td><td>回款金额（元）</td><td>必须 &gt; 0</td></tr><tr><td>currency</td><td>char(3)</td><td>是</td><td>币种</td><td>默认 CNY</td></tr><tr><td>bank_reference</td><td>varchar(100)</td><td>否</td><td>银行流水参考号</td><td>脱敏，不保存敏感账号</td></tr><tr><td>remark</td><td>varchar(500)</td><td>否</td><td>备注</td><td></td></tr></tbody></table><p>唯一约束：<code>collection_no</code>。关联校验：累计有效回款超过应收金额时阻止发布，除非 CFO 明确允许溢收。</p><h3 id="_5-7-planned-expense——计划支出" tabindex="-1">5.7 planned_expense——计划支出 <a class="header-anchor" href="#_5-7-planned-expense——计划支出" aria-label="Permalink to &quot;5.7 planned_expense——计划支出&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>Excel 字段</th><th>业务定义/校验</th></tr></thead><tbody><tr><td>expense_no</td><td>varchar(64)</td><td>是</td><td>支出计划编号</td><td>稳定唯一编号</td></tr><tr><td>expense_name</td><td>varchar(200)</td><td>是</td><td>支出名称</td><td>经营可读名称</td></tr><tr><td>category</td><td>varchar(100)</td><td>是</td><td>支出类别</td><td>V3 分类枚举待财务确认</td></tr><tr><td>planned_date</td><td>date</td><td>是</td><td>计划支出日期</td><td>参与当月计划支出统计</td></tr><tr><td>planned_amount</td><td>numeric(18,2)</td><td>是</td><td>计划金额（元）</td><td>必须 &gt; 0</td></tr><tr><td>owner_code</td><td>varchar(64)</td><td>是</td><td>责任人编号</td><td></td></tr><tr><td>owner_name</td><td>varchar(100)</td><td>是</td><td>责任人名称</td><td></td></tr><tr><td>rigidity</td><td>varchar(16)</td><td>是</td><td>刚性程度</td><td>rigid/deferrable，待 CFO 确认</td></tr><tr><td>approval_status</td><td>varchar(20)</td><td>是</td><td>审批状态</td><td>planned/pending/approved/cancelled</td></tr><tr><td>remark</td><td>varchar(500)</td><td>否</td><td>备注</td><td></td></tr></tbody></table><p>唯一约束：<code>(expense_no, import_batch_id)</code>；<code>cancelled</code> 不参与计划支出。</p><h3 id="_5-8-followup-record——回款跟进记录" tabindex="-1">5.8 followup_record——回款跟进记录 <a class="header-anchor" href="#_5-8-followup-record——回款跟进记录" aria-label="Permalink to &quot;5.8 followup_record——回款跟进记录&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>uuid</td><td>是</td><td>主键</td></tr><tr><td>receivable_id</td><td>uuid</td><td>是</td><td>应收事项</td></tr><tr><td>followed_at</td><td>timestamptz</td><td>是</td><td>跟进时间</td></tr><tr><td>followed_by_code</td><td>varchar(64)</td><td>是</td><td>跟进人编号</td></tr><tr><td>followed_by_name</td><td>varchar(100)</td><td>是</td><td>跟进人名称</td></tr><tr><td>content</td><td>varchar(1000)</td><td>是</td><td>跟进结果</td></tr><tr><td>next_followup_date</td><td>date</td><td>否</td><td>下次跟进日期</td></tr><tr><td>promised_collection_date</td><td>date</td><td>否</td><td>客户承诺到账日期，是否替代 expected_date 待确认</td></tr><tr><td>created_at</td><td>timestamptz</td><td>是</td><td>创建时间</td></tr></tbody></table><h3 id="_5-9-task——待处理任务" tabindex="-1">5.9 task——待处理任务 <a class="header-anchor" href="#_5-9-task——待处理任务" aria-label="Permalink to &quot;5.9 task——待处理任务&quot;">​</a></h3><p>任务是规则产物，不由 Excel 直接导入。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>uuid</td><td>是</td><td>主键</td></tr><tr><td>task_type</td><td>varchar(32)</td><td>是</td><td>cash_gap/collection_overdue/expense_review/owner_missing</td></tr><tr><td>source_type</td><td>varchar(32)</td><td>是</td><td>receivable/planned_expense/batch/system</td></tr><tr><td>source_id</td><td>uuid</td><td>否</td><td>来源对象</td></tr><tr><td>title</td><td>varchar(200)</td><td>是</td><td>任务标题</td></tr><tr><td>risk_level</td><td>varchar(16)</td><td>是</td><td>green/yellow/red</td></tr><tr><td>owner_code</td><td>varchar(64)</td><td>否</td><td>责任人编号</td></tr><tr><td>owner_name</td><td>varchar(100)</td><td>否</td><td>责任人名称</td></tr><tr><td>due_date</td><td>date</td><td>是</td><td>处理截止日</td></tr><tr><td>status</td><td>varchar(20)</td><td>是</td><td>pending/in_progress/completed/closed</td></tr><tr><td>boss_intervention_required</td><td>boolean</td><td>是</td><td>是否需要老板介入</td></tr><tr><td>rule_version</td><td>varchar(20)</td><td>是</td><td>生成任务的规则版本</td></tr><tr><td>created_at</td><td>timestamptz</td><td>是</td><td>创建时间</td></tr><tr><td>updated_at</td><td>timestamptz</td><td>是</td><td>更新时间</td></tr><tr><td>version</td><td>integer</td><td>是</td><td>乐观锁</td></tr></tbody></table><p>建议唯一约束：同一 <code>source_type + source_id + task_type + due_date</code> 不重复生成未关闭任务。</p><h2 id="_6-索引建议" tabindex="-1">6. 索引建议 <a class="header-anchor" href="#_6-索引建议" aria-label="Permalink to &quot;6. 索引建议&quot;">​</a></h2><ul><li><code>import_batch(status, created_at desc)</code></li><li><code>raw_import_row(import_batch_id, validation_status)</code></li><li><code>account_balance(snapshot_date desc, account_code)</code></li><li><code>receivable(agreed_due_date, source_status)</code></li><li><code>receivable(customer_id, owner_code)</code></li><li><code>collection(receivable_id, collection_date)</code></li><li><code>planned_expense(planned_date, approval_status)</code></li><li><code>task(status, due_date, risk_level)</code></li><li><code>followup_record(receivable_id, followed_at desc)</code></li></ul><h2 id="_7-v3-暂缓冻结项" tabindex="-1">7. V3 暂缓冻结项 <a class="header-anchor" href="#_7-v3-暂缓冻结项" aria-label="Permalink to &quot;7. V3 暂缓冻结项&quot;">​</a></h2><ul><li>一笔回款分摊到多笔应收：真实样本若存在，增加 <code>collection_allocation</code> 关联表。</li><li>多币种折算：V3 仅支持 CNY；汇率和折算日期后续设计。</li><li>预算与支出审批：待 CFO 提供预算维度及审批数据后扩展。</li><li>客户主数据独立维护：V3 可从应收数据派生。</li><li>组织、账号和 RBAC：阶段 4 处理。</li></ul><h2 id="_8-cfo-产品待确认" tabindex="-1">8. CFO/产品待确认 <a class="header-anchor" href="#_8-cfo-产品待确认" aria-label="Permalink to &quot;8. CFO/产品待确认&quot;">​</a></h2><ol><li>应收金额是当期应收还是合同总额。</li><li>预计回款按约定到账日还是最新承诺日期统计。</li><li>部分回款后的逾期口径。</li><li>超额回款、退款、冲销如何表达。</li><li>计划支出包含哪些审批状态和固定支出。</li><li>账户可用余额是否已扣除受限资金。</li><li>风险阈值、金额阈值及老板介入条件。</li><li>一笔回款是否可能对应多笔应收。</li><li>各数据类型采用全量覆盖还是增量更新。</li></ol>',37))])}const A=o(s,[["render",p]]);export{f as __pageData,A as default};
